        shots = task.shots or 1
        qubits = max(task.qubits_required, 1)

        # 量子比特·小时 = qubits × 执行时间
        qubit_hours = (qubits * task.estimated_time) / 3600.0

        # 总门操作数 ≈ depth × shots
        total_gate_ops = depth * shots

